// Seed workspaces for in-app "Load Case Study" feature.
// Each seed is a pre-built Learning Companion workspace that can replace
// the current workspace with a single click.
// Seed data is generated by `npm run demo:case-study`.

let cachedSeed = null;

async function loadEcomPsychSeed() {
  if (cachedSeed) return cachedSeed;
  try {
    const mod = await import("./generated/ecom-psych-seed.json", { with: { type: "json" } });
    cachedSeed = mod.default;
  } catch {
    cachedSeed = null;
  }
  return cachedSeed;
}

export const SEED_WORKSPACES = [
  {
    id: "ecom-psych-v1.3",
    labelEn: "E-commerce Psychology Course",
    labelZh: "电商心理学实战课",
    descriptionEn: "30-day bilingual e-commerce psychology course with captures, review cards, TTS segments, and exercises (W1 D1-D3 with real content).",
    descriptionZh: "30天双语电商心理学课程，包含摘录、复习卡片、TTS片段和练习（W1 D1-D3已有内容）。",
    getWorkspace: async () => await loadEcomPsychSeed(),
  },
];
